import{_ as t,o as a,c as i,ag as n}from"./chunks/framework.CT-gmSiP.js";const u=JSON.parse(`{"title":"Entity Generator","description":"Designer visuel d'entites avec generation de code multi-couche","frontmatter":{"title":"Entity Generator","description":"Designer visuel d'entites avec generation de code multi-couche"},"headers":[],"relativePath":"frontend/pages/entity-generator.md","filePath":"frontend/pages/entity-generator.md"}`),s={name:"frontend/pages/entity-generator.md"};function r(o,e,d,l,c,p){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="entity-generator" tabindex="-1">Entity Generator <a class="header-anchor" href="#entity-generator" aria-label="Permalink to &quot;Entity Generator&quot;">​</a></h1><p>Le Entity Generator est un outil visuel pour designer des entites et generer automatiquement le code C# et TypeScript associe.</p><p><strong>Fichiers sources</strong> :</p><ul><li><code>frontend/src/pages/generator/EntityDesigner.tsx</code> -- composant principal</li><li><code>frontend/src/pages/generator/codeGenerator.ts</code> -- generateurs de code</li><li><code>frontend/src/pages/generator/types.ts</code> -- types TypeScript</li></ul><p><strong>Route</strong> : <code>/admin/generator</code></p><h2 id="layout-en-3-panneaux" tabindex="-1">Layout en 3 panneaux <a class="header-anchor" href="#layout-en-3-panneaux" aria-label="Permalink to &quot;Layout en 3 panneaux&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Panneau</th><th>Largeur</th><th>Contenu</th></tr></thead><tbody><tr><td>Gauche</td><td>224px</td><td>Liste des entites, bouton ajouter</td></tr><tr><td>Centre</td><td>flexible</td><td>Formulaire d&#39;edition de l&#39;entite selectionnee</td></tr><tr><td>Droit</td><td>420px</td><td>Preview du code genere avec onglets</td></tr><tr><td>Bas (optionnel)</td><td>100%</td><td>Diagramme ER en SVG</td></tr></tbody></table><h2 id="_8-types-de-champs" tabindex="-1">8 types de champs <a class="header-anchor" href="#_8-types-de-champs" aria-label="Permalink to &quot;8 types de champs&quot;">​</a></h2><p>Les types disponibles pour les champs d&#39;entite :</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> FieldType</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;string&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;int&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;decimal&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;bool&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;DateTime&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Guid&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;enum&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;relation&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h3 id="champs-speciaux" tabindex="-1">Champs speciaux <a class="header-anchor" href="#champs-speciaux" aria-label="Permalink to &quot;Champs speciaux&quot;">​</a></h3><ul><li><strong>enum</strong> : un champ supplementaire apparait pour saisir les valeurs (comma-separated)</li><li><strong>relation</strong> : deux selects apparaissent pour choisir l&#39;entite cible et le type de relation (<code>one-to-one</code>, <code>one-to-many</code>, <code>many-to-many</code>)</li></ul><h2 id="formulaire-d-edition" tabindex="-1">Formulaire d&#39;edition <a class="header-anchor" href="#formulaire-d-edition" aria-label="Permalink to &quot;Formulaire d&#39;edition&quot;">​</a></h2><p>Chaque entite expose les proprietes suivantes :</p><table tabindex="0"><thead><tr><th>Propriete</th><th>Description</th></tr></thead><tbody><tr><td><code>name</code></td><td>Nom de l&#39;entite (auto-genere : pluriel, prefix API)</td></tr><tr><td><code>pluralName</code></td><td>Nom pluriel (auto-calcule)</td></tr><tr><td><code>description</code></td><td>Description optionnelle</td></tr><tr><td><code>apiPrefix</code></td><td>Prefix de route API (auto-calcule)</td></tr><tr><td><code>hasAudit</code></td><td>Ajoute CreatedAt, UpdatedAt</td></tr><tr><td><code>hasSoftDelete</code></td><td>Ajoute IsDeleted</td></tr><tr><td><code>hasTenantId</code></td><td>Ajoute TenantId</td></tr></tbody></table><p>La table de champs inclut des colonnes : Name, Type, Required, Searchable, Filterable, Show in List, Show in Form.</p><h2 id="generateurs-de-code" tabindex="-1">Generateurs de code <a class="header-anchor" href="#generateurs-de-code" aria-label="Permalink to &quot;Generateurs de code&quot;">​</a></h2><p>Le fichier <code>codeGenerator.ts</code> genere 8 fichiers de code pour chaque entite :</p><ol><li><strong>Domain Entity</strong> (<code>Entity.cs</code>) -- classe C# avec proprietes</li><li><strong>DTO</strong> (<code>EntityDto.cs</code>) -- Data Transfer Object</li><li><strong>Application Service</strong> (<code>EntityService.cs</code>)</li><li><strong>EF Configuration</strong> (<code>EntityConfiguration.cs</code>)</li><li><strong>API Controller</strong> (<code>EntityController.cs</code>)</li><li><strong>TypeScript Interface</strong> (<code>entity.ts</code>)</li><li><strong>React Form Component</strong> (<code>EntityForm.tsx</code>)</li><li><strong>React List Component</strong> (<code>EntityList.tsx</code>)</li></ol><p>Les onglets dans le panneau droit affichent chaque fichier genere avec coloration syntaxique et bouton &quot;Copy&quot;.</p><h2 id="diagramme-er-svg" tabindex="-1">Diagramme ER (SVG) <a class="header-anchor" href="#diagramme-er-svg" aria-label="Permalink to &quot;Diagramme ER (SVG)&quot;">​</a></h2><p>Le bouton &quot;Show ER Diagram&quot; affiche un diagramme entite-relation en SVG :</p><ul><li>Chaque entite est representee par un rectangle avec en-tete bleu et liste de champs</li><li>Les relations sont tracees en courbes de Bezier avec fleches</li><li>Les labels de relation (1:N, etc.) sont affiches au milieu des courbes</li></ul><h2 id="telechargement" tabindex="-1">Telechargement <a class="header-anchor" href="#telechargement" aria-label="Permalink to &quot;Telechargement&quot;">​</a></h2><p>Le bouton &quot;Generate All&quot; telecharge chaque fichier individuellement via <code>Blob</code> + <code>URL.createObjectURL</code>.</p><h2 id="preview-uml" tabindex="-1">Preview UML <a class="header-anchor" href="#preview-uml" aria-label="Permalink to &quot;Preview UML&quot;">​</a></h2><p>Un composant <code>EntityCard</code> affiche une preview style UML de l&#39;entite selectionnee avec les champs, les types, et les annotations (Audit, SoftDelete, Tenant).</p>`,27)])])}const g=t(s,[["render",r]]);export{u as __pageData,g as default};
